```class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string res, temp;
        for (char c : s) {
            if (c != '-') {
                if (islower(c)) c = toupper(c);
                temp += c;
            }
        }
        int len = temp.length();
        res += temp.substr(0, len % k ? len % k : k);
        for (int i = len % k; i < len; i += k) {
            res += '-';
            res += temp.substr(i, k);
        }
        return res;
    }
};
